{"nbformat":4,"nbformat_minor":0,"metadata":{"colab":{"provenance":[],"authorship_tag":"ABX9TyMstVa6gFMgUaXjaryLg416"},"kernelspec":{"name":"python3","display_name":"Python 3"},"language_info":{"name":"python"}},"cells":[{"cell_type":"markdown","source":["# AI Password Strength Checker Lite"],"metadata":{"id":"qvT24880dkiQ"}},{"cell_type":"code","execution_count":null,"metadata":{"colab":{"base_uri":"https://localhost:8080/"},"id":"1c6E4xIIaqxm","outputId":"fc2a7a35-98b2-4451-e7cf-8752b6eb0284"},"outputs":[{"output_type":"stream","name":"stdout","text":["Enter password: ilyas\n","Password strength: Very Weak\n","Remaining attempts: 4\n","The password is not strong enough.\n"]}],"source":["attempt = 5\n","count = 0\n","\n","while count <= attempt:\n","    password = input(\"Enter password: \")\n","\n","    check_length = len(password) >= 8\n","    check_digit = any(char.isdigit() for char in password)\n","    check_uppercase = any(char.isupper() for char in password)\n","\n","    check_condition = sum([check_length, check_digit, check_uppercase])\n","\n","    if check_condition == 0:\n","        Strength = \"Very Weak\"\n","    elif check_condition == 1:\n","        Strength = \"Weak\"\n","    elif check_condition == 2:\n","        Strength = \"Moderate \"\n","    else:\n","        Strength = \"Strong\"\n","\n","    print(f\"Password strength: {Strength}\")\n","\n","    count += 1\n","    remaining = attempt - count\n","    print(f\"Remaining attempts: {remaining}\")\n","\n","    if Strength == \"Strong\":\n","        print(\"Strong password accepted.\")\n","        break\n","    else:\n","        print(\"The password is not strong enough.\")\n","\n","if count == attempt and Strength != \"Strong\":\n","    print(\"You have used all attempt Try again later.\")"]},{"cell_type":"code","source":[],"metadata":{"id":"85AfT28Oaz6Z"},"execution_count":null,"outputs":[]}]}